@DamianOsipiuk Please merge this PR, this is important for use queryOptions as component props ex:

```ts
const Comp = defineComponent({
  props: {
    queryOptions: Object,
  },
  setup: (props) => {
    return useQuery(
      computed(() => ({
        ...props.queryOptions,
        queryFn: () => {
           // ...
        }
      }))
    )
  }
})
```

